INSERT INTO public.logistics_packaging_rules (rule_key, payload) VALUES ('overhang', '{"rule":"Loads are centered on the pallet. Allowed overhang is total extra footprint, split equally on every side.","example":"10 cm overhang means +5 cm left, +5 cm right, +5 cm front, +5 cm back.","splitAcrossSides":true,"floorLoadedContainerOverhangAllowed":false}'::jsonb);
INSERT INTO public.logistics_packaging_rules (rule_key, payload) VALUES ('palletLoadedContainer', '{"rule":"Pallets inside a pallet-loaded container must fit within the container internal length and width. Pallet plus cargo height must not exceed internal height minus 10 cm.","palletFootprintCm":{"width":100,"length":120,"height":15},"showPalletsInsideContainer":true,"loadingSequence":"Fill one pallet position from bottom to top before loading the next pallet position."}'::jsonb);
INSERT INTO public.logistics_packaging_rules (rule_key, payload) VALUES ('rondoKvadro100125', '{"appliesToCodes":["RN100","RN125","KV100","KV125","RN100.CO","RN125.CO"],"layerPattern":["Layer A: 4 boxes along the left pallet length using 32+32+32+32 cm and 2 boxes along the right pallet length using 62+62 cm.","Layer B: mirrored for stability, 4 boxes on the right and 2 boxes on the left."],"alternatingLayers":true}'::jsonb);
INSERT INTO public.logistics_packaging_rules (rule_key, payload) VALUES ('floorLoadedContainer', '{"rule":"No pallet and no overhang. Products are stacked from the container floor up. Container internal length, width and height are the hard limits.","example":"40HQ floor-loaded container should be evaluated by internal dimensions only for RONDO/KVADRO 100/125 capacity."}'::jsonb);
INSERT INTO public.logistics_packaging_rules (rule_key, payload) VALUES ('lineoLayering', '{"rule":"If LINEO models fit by pallet length and width, alternate layers by 90 degrees.","alternatingLayers":true}'::jsonb);